class Solution:
    def largestSumOfAverages(self, nums, k):
        import sys
        from functools import lru_cache
        sys.setrecursionlimit(10000)
        n = len(nums)
        prefix = [0.0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        @lru_cache(None)
        def best(start, groups):
            if groups == 1:
                return (prefix[n] - prefix[start]) / (n - start)
            res = 0.0
            # leave at least groups-1 elements for the remaining groups
            for end in range(start + 1, n - groups + 2):
                avg = (prefix[end] - prefix[start]) / (end - start)
                res = max(res, avg + best(end, groups - 1))
            return res
        return best(0, k)

