class Solution:
    def largestSumOfAverages(self, nums, k):
        n = len(nums)
        prefix = [0.0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        def avg(i, j):
            return (prefix[j] - prefix[i]) / (j - i)
        # dp[i] = best score for nums[i:] with current group budget
        dp = [avg(i, n) for i in range(n)] + [0.0]
        for _ in range(k - 1):
            ndp = dp[:]
            for i in range(n):
                for j in range(i + 1, n):
                    ndp[i] = max(ndp[i], avg(i, j) + dp[j])
            dp = ndp
        return dp[0]

