var largestSumOfAverages = function(nums, k) {
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
    const avg = (i, j) => (prefix[j] - prefix[i]) / (j - i);
    let dp = new Array(n + 1);
    for (let i = 0; i <= n; i++) dp[i] = i < n ? avg(i, n) : 0;
    for (let g = 0; g < k - 1; g++) {
        const ndp = dp.slice();
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                ndp[i] = Math.max(ndp[i], avg(i, j) + dp[j]);
            }
        }
        dp = ndp;
    }
    return dp[0];
};
